import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.InetAddress;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

/**
 * A service to fetch and preview content from a given URL.
 * This is commonly used for generating link previews in applications.
 */
public class UrlPreviewService {

    private static final int CONNECT_TIMEOUT = 5000;
    private static final int READ_TIMEOUT = 5000;
    private static final int MAX_REDIRECTS = 5;

    /**
     * Fetches the content from the provided URL string and returns a summary.
     * The summary is the first few lines of the resource content.
     *
     * @param urlString The URL of the resource to fetch.
     * @return A string containing a preview of the content, or an error message if fetching fails.
     */
    public String getUrlContentPreview(String urlString) {
        if (urlString == null || urlString.trim().isEmpty()) {
            return "Error: Empty URL provided.";
        }

        HttpURLConnection connection = null;
        try {
            URL url = new URL(urlString);
            int redirects = 0;
            Set<String> visitedUrls = new HashSet<>();

            while (redirects < MAX_REDIRECTS) {
                // 1. Validate Protocol (Allow only HTTP/HTTPS)
                String protocol = url.getProtocol().toLowerCase();
                if (!"http".equals(protocol) && !"https".equals(protocol)) {
                    throw new SecurityException("Blocked protocol: " + protocol);
                }

                // 2. Validate Host/IP (Prevent SSRF to internal network)
                validateHost(url.getHost());

                // 3. Open Connection
                connection = (HttpURLConnection) url.openConnection();
                connection.setConnectTimeout(CONNECT_TIMEOUT);
                connection.setReadTimeout(READ_TIMEOUT);
                // Disable automatic redirects to validate the next URL
                connection.setInstanceFollowRedirects(false); 

                int status = connection.getResponseCode();

                // 4. Handle Redirects Manually
                if (status >= 300 && status < 400) {
                    String newUrlString = connection.getHeaderField("Location");
                    if (newUrlString == null) {
                        return "Error: Redirect status without Location header.";
                    }

                    // Handle relative redirects
                    url = new URL(url, newUrlString);

                    if (visitedUrls.contains(url.toString())) {
                        return "Error: Circular redirect detected.";
                    }
                    visitedUrls.add(url.toString());

                    redirects++;
                    connection.disconnect(); // Close previous connection
                    continue;
                }

                // 5. Read Content if successful
                if (status >= 200 && status < 300) {
                    try (BufferedReader reader = new BufferedReader(
                            new InputStreamReader(connection.getInputStream(), StandardCharsets.UTF_8))) {
                        return reader.lines().limit(5).collect(Collectors.joining("\n"));
                    }
                } else {
                    return "Error: HTTP " + status;
                }
            }

            return "Error: Too many redirects.";

        } catch (SecurityException se) {
            // Log this as a security event in a real application
            return "Security Error: " + se.getMessage();
        } catch (Exception e) {
            return "Error fetching content from URL: " + e.getMessage();
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }

    /**
     * Resolves the host to an IP address and checks if it belongs to a private/local network.
     *
     * @param host The hostname to validate.
     * @throws Exception If the host is invalid or resolves to a blocked IP.
     */
    private void validateHost(String host) throws Exception {
        InetAddress address = InetAddress.getByName(host);

        if (address.isLoopbackAddress() || 
            address.isSiteLocalAddress() || 
            address.isLinkLocalAddress() || 
            address.isAnyLocalAddress() || 
            address.isMulticastAddress()) {
            throw new SecurityException("Access to internal/private network is denied.");
        }
    }
}

