            // Read the content using try-with-resources to ensure stream closure
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(connection.getInputStream(), StandardCharsets.UTF_8))) {

                char[] buffer = new char[1024]; // 1KB buffer
                int charsRead = reader.read(buffer, 0, 1024);

                if (charsRead != -1) {
                    return new String(buffer, 0, charsRead);
                }
            }

        } catch (Exception e) {
            // Requirement: If the request fails or the URL is invalid, return an empty string.
            // In a real application, logging the exception here is recommended.
            return "";
        }

        return "";
    }
}
